    topic_id: topicId,
    rounds_completed: roundSummaries.length,
    final_verdict: finalVerdict,
    stability_score: finalScore ? finalScore.verdict_delta : null,
    stop_reason: stopReason || 'max_rounds_per_topic',
    rounds: roundSummaries,
  };
}

