75: function parseJsonl(filePath) {
76:   const lines = fs.readFileSync(filePath, 'utf8').split(/\r?\n/);
77:   const events = [];
78:   lines.forEach((line, index) => {
79:     const trimmed = line.trim();
80:     if (!trimmed) return;
81:     try {
82:       const event = JSON.parse(trimmed);
83:       if (!event || typeof event !== 'object' || Array.isArray(event)) {
84:         throw new Error('line is not a JSON object');
85:       }
86:       events.push(event);
87:     } catch (error) {
88:       throw new Error(`Malformed JSONL at ${filePath}:${index + 1}: ${error.message}`);
89:     }
90:   });
91:   return events;
92: }
