94: function roundIdFor(value) {
95:   if (typeof value === 'string' && /^round-\d{3}$/.test(value)) return value;
96:   const numeric = Number(value || 1);
97:   if (Number.isInteger(numeric) && numeric > 0) return `round-${String(numeric).padStart(3, '0')}`;
98:   return String(value || 'round-001').replace(/[^A-Za-z0-9._:-]+/g, '-');
99: }
100: 
101: function slug(value) {
102:   return String(value || 'unknown')
103:     .trim()
104:     .replace(/[^A-Za-z0-9._:-]+/g, '-')
105:     .replace(/^-+|-+$/g, '')
106:     .slice(0, 120) || 'unknown';
107: }
108: 
109: function eventSessionId(event) {
110:   return event.session_id || event.sessionId || null;
111: }
112: 
113: function eventRoundId(event) {
114:   return roundIdFor(event.round_id || event.roundId || event.round);
115: }
116: 
117: function eventSeatId(event) {
118:   return event.seat_id || event.seatId || event.seat || null;
119: }
120: 
121: function addNode(nodes, node) {
122:   if (!node.id) return;
123:   if (!nodes.has(node.id)) nodes.set(node.id, node);
124: }
125: 
126: function addPendingEdge(edges, edge) {
127:   if (!edge.id || !edge.sourceId || !edge.targetId || edge.sourceId === edge.targetId) return;
128:   if (!edges.has(edge.id)) edges.set(edge.id, edge);
129: }
