131: function graphItems(event) {
132:   const pairs = [
133:     ['claims', 'CLAIM'],
134:     ['claim', 'CLAIM'],
135:     ['evidence', 'EVIDENCE'],
136:     ['evidenceItems', 'EVIDENCE'],
137:     ['disagreements', 'DISAGREEMENT'],
138:     ['disagreement', 'DISAGREEMENT'],
139:     ['decisions', 'DECISION'],
140:     ['decision', 'DECISION'],
141:     ['recommendations', 'RECOMMENDATION'],
142:     ['recommendation', 'RECOMMENDATION'],
143:   ];
144:   const result = [];
145:   for (const [key, kind] of pairs) {
146:     const value = event[key];
147:     const items = Array.isArray(value) ? value : value ? [value] : [];
148:     for (const item of items) result.push({ kind, item });
149:   }
150:   return result;
151: }
