153: function itemId(kind, item, index, roundId) {
154:   if (typeof item === 'string') return `${kind.toLowerCase()}:${slug(item)}`;
155:   return String(item.id || item.nodeId || item.key || `${kind.toLowerCase()}:${roundId}:${index + 1}`);
156: }
157: 
158: function itemName(kind, item, id) {
159:   if (typeof item === 'string') return item;
160:   return String(item.name || item.title || item.summary || item.text || `${kind} ${id}`);
161: }
162: 
163: function itemMetadata(item, event) {
164:   if (typeof item !== 'object' || item === null || Array.isArray(item)) {
165:     return { sourceEvent: event.event || 'unknown' };
166:   }
167:   const {
168:     id,
169:     nodeId,
170:     key,
171:     name,
172:     title,
173:     summary,
174:     text,
175:     supports,
176:     contradicts,
177:     resolves,
178:     evidenceFor,
179:     recommends,
180:     derivesFrom,
181:     agreesWith,
182:     targetId,
183:     target_id,
184:     ...rest
185:   } = item;
186:   return { sourceEvent: event.event || 'unknown', ...rest };
187: }
188: 
189: function asTargets(value) {
190:   if (!value) return [];
191:   return (Array.isArray(value) ? value : [value]).map((item) => String(item)).filter(Boolean);
192: }
193: 
194: function collectDeclaredEdges(item, sourceId) {
195:   if (typeof item !== 'object' || item === null || Array.isArray(item)) return [];
196:   return [
197:     ['supports', 'SUPPORTS'],
198:     ['contradicts', 'CONTRADICTS'],
199:     ['resolves', 'RESOLVES'],
200:     ['evidenceFor', 'EVIDENCE_FOR'],
201:     ['recommends', 'RECOMMENDS'],
202:     ['derivesFrom', 'DERIVES_FROM'],
203:     ['agreesWith', 'AGREES_WITH'],
204:     ['targetId', defaultRelationForTarget(item)],
205:     ['target_id', defaultRelationForTarget(item)],
206:   ].flatMap(([field, relation]) => asTargets(item[field]).map((targetId) => ({
207:     sourceId,
208:     targetId,
209:     relation,
210:   })));
211: }
212: 
213: function defaultRelationForTarget(item) {
214:   const type = String(item.kind || item.type || '').toUpperCase();
215:   if (type === 'DISAGREEMENT') return 'CONTRADICTS';
216:   if (type === 'EVIDENCE') return 'EVIDENCE_FOR';
217:   if (type === 'RECOMMENDATION') return 'RECOMMENDS';
218:   if (type === 'CLAIM') return 'SUPPORTS';
219:   return 'DERIVES_FROM';
220: }
