226: /**
227:  * Derive a council runtime graph payload from a sequence of council state
228:  * events. Walks every event, creates SESSION/ROUND/SEAT/CLAIM/EVIDENCE/
229:  * DISAGREEMENT/DECISION/RECOMMENDATION nodes, and adds relationship edges
230:  * declared in the artifact and inferred from item types.
231:  *
232:  * @param {string} specFolder - Spec folder path for namespace isolation.
233:  * @param {string} sessionId - Council session identifier.
234:  * @param {Array<Object>} events - Parsed AI council state events from
235:  *   ai-council-state.jsonl.
236:  * @returns {{ specFolder: string, sessionId: string, nodes: Array<Object>, edges: Array<Object> }}
237:  *   Council graph upsert payload.
238:  */
239: function derivePayload(specFolder, sessionId, events) {
240:   const nodes = new Map();
241:   const edges = new Map();
242:   const sessionNodeId = `session:${slug(sessionId)}`;
243: 
244:   addNode(nodes, {
245:     id: sessionNodeId,
246:     kind: 'SESSION',
247:     name: `Council session ${sessionId}`,
248:     artifactPath: 'ai-council/ai-council-state.jsonl',
249:     metadata: { replayedFrom: 'ai-council-state.jsonl' },
250:   });
251: 
252:   events.forEach((event, eventIndex) => {
253:     const explicitSession = eventSessionId(event);
254:     if (explicitSession && explicitSession !== sessionId) return;
255: 
256:     const roundId = eventRoundId(event);
257:     const roundNodeId = `round:${roundId}`;
258:     addNode(nodes, {
259:       id: roundNodeId,
260:       kind: 'ROUND',
261:       name: `Council ${roundId}`,
262:       artifactPath: 'ai-council/ai-council-state.jsonl',
263:       roundId,
264:       metadata: { sourceEvent: event.event || 'unknown', eventIndex },
265:     });
266:     addPendingEdge(edges, {
267:       id: `edge:${roundNodeId}:session`,
268:       sourceId: roundNodeId,
269:       targetId: sessionNodeId,
270:       relation: 'DERIVES_FROM',
271:       artifactPath: 'ai-council/ai-council-state.jsonl',
272:       metadata: { sourceEvent: event.event || 'unknown' },
273:     });
274: 
275:     const seatIds = new Set(asTargets(event.seats));
276:     const directSeatId = eventSeatId(event);
277:     if (directSeatId) seatIds.add(String(directSeatId));
278: 
279:     for (const seatId of seatIds) {
280:       const seatNodeId = `seat:${slug(seatId)}`;
281:       addNode(nodes, {
282:         id: seatNodeId,
283:         kind: 'SEAT',
284:         name: `Council seat ${seatId}`,
285:         artifactPath: event.path ? `ai-council/${event.path}` : 'ai-council/ai-council-state.jsonl',
286:         roundId,
287:         metadata: { sourceEvent: event.event || 'unknown', status: event.status || null },
288:       });
289:       addPendingEdge(edges, {
290:         id: `edge:${seatNodeId}:${roundNodeId}`,
291:         sourceId: seatNodeId,
292:         targetId: roundNodeId,
293:         relation: 'PARTICIPATES_IN',
294:         artifactPath: 'ai-council/ai-council-state.jsonl',
295:         metadata: { sourceEvent: event.event || 'unknown' },
296:       });
297:     }
298: 
299:     graphItems(event).forEach(({ kind, item }, itemIndex) => {
300:       const id = itemId(kind, item, itemIndex, roundId);
301:       addNode(nodes, {
302:         id,
303:         kind,
304:         name: itemName(kind, item, id),
305:         artifactPath: event.path ? `ai-council/${event.path}` : 'ai-council/ai-council-state.jsonl',
306:         roundId,
307:         metadata: itemMetadata(item, event),
308:       });
309: 
310:       if (directSeatId) {
311:         const seatNodeId = `seat:${slug(directSeatId)}`;
312:         const relation = kind === 'DISAGREEMENT'
313:           ? 'CONTRADICTS'
314:           : kind === 'RECOMMENDATION'
315:             ? 'RECOMMENDS'
316:             : 'PROPOSES';
317:         addPendingEdge(edges, {
318:           id: `edge:${seatNodeId}:${id}:${relation.toLowerCase()}`,
319:           sourceId: seatNodeId,
320:           targetId: id,
321:           relation,
322:           artifactPath: event.path ? `ai-council/${event.path}` : 'ai-council/ai-council-state.jsonl',
323:           metadata: { sourceEvent: event.event || 'unknown' },
324:         });
325:       }
326: 
327:       for (const declared of collectDeclaredEdges(item, id)) {
328:         addPendingEdge(edges, {
329:           id: `edge:${id}:${declared.targetId}:${declared.relation.toLowerCase()}`,
330:           sourceId: id,
331:           targetId: declared.targetId,
332:           relation: declared.relation,
333:           artifactPath: event.path ? `ai-council/${event.path}` : 'ai-council/ai-council-state.jsonl',
334:           metadata: { sourceEvent: event.event || 'unknown' },
335:         });
336:       }
337:     });
338:   });
339: 
340:   const nodeIds = new Set(nodes.keys());
341:   const validEdges = [...edges.values()].filter((edge) => nodeIds.has(edge.sourceId) && nodeIds.has(edge.targetId));
342: 
343:   return {
344:     specFolder,
345:     sessionId,
346:     nodes: [...nodes.values()],
347:     edges: validEdges,
348:   };
349: }
