351: function runRuntimeUpsert(payload, repoRoot) {
352:   const scriptPath = runtimeUpsertScript(repoRoot);
353:   const childEnv = { ...process.env };
354:   delete childEnv.DEEP_LOOP_TSX_LOADED;
355:   const child = spawnSync(process.execPath, [
356:     scriptPath,
357:     '--spec-folder',
358:     payload.specFolder,
359:     '--loop-type',
360:     'council',
361:     '--session-id',
362:     payload.sessionId,
363:     '--nodes',
364:     JSON.stringify(payload.nodes),
365:     '--edges',
366:     JSON.stringify(payload.edges),
367:   ], {
368:     cwd: repoRoot,
369:     env: childEnv,
370:     encoding: 'utf8',
371:     stdio: ['ignore', 'pipe', 'pipe'],
372:   });
373: 
374:   if (child.stdout) process.stdout.write(child.stdout);
375:   if (child.stderr) process.stderr.write(child.stderr);
376: 
377:   const exitCode = child.status === null ? 1 : child.status;
378:   if (exitCode !== 0) {
379:     const err = new Error(`Runtime council graph upsert failed with exit code ${exitCode}`);
380:     err.exitCode = exitCode;
381:     throw err;
382:   }
383: 
384:   return exitCode;
385: }
